<?phprequire("DEA_db.php");$session_id=$_POST['session_id'];$num_of_fields=$_POST['num_of_fields'];$conjunction=$_POST['conjunction'];for($i=0;$i<$num_of_fields;$i++){    $ii=$i+1;	if($ii<10)	{		$field_id[$i]=$_POST['field_id0'.$ii];		$field_value[$i]=$_POST['field_value0'.$ii];	}	else	{		$field_id[$i]=$_POST['field_id'.$ii];		$field_value[$i]=$_POST['field_value'.$ii];	}}echo '<?xml version="1.0"?><records>';if($num_of_fields>0) search_record($session_id, $field_id, $field_value, $num_of_fields,$conjunction);echo '</records>';?>